"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["754340"],{878395(e){e.exports=JSON.parse('{"tag":{"label":"spawner","permalink":"/dst-api-webdocs/docs/tags/spawner","allTagsPath":"/dst-api-webdocs/docs/tags","count":52,"items":[{"id":"game-scripts/map/static_layouts/barracks","title":"Barracks","description":"Tiled map layout data defining the static structure of the Barracks level, including background tiles, foreground object placements, and spawner entities for ruins and nightmare chess pieces.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/barracks"},{"id":"game-scripts/map/static_layouts/barracks_two","title":"Barracks Two","description":"A static layout definition for the Ruins map section that specifies background tiles, foreground objects (ruins walls, broken walls), and spawner placements for monsters and decoratives.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/barracks_two"},{"id":"game-scripts/map/static_layouts/brinepool1","title":"Brinepool1","description":"A static map layout definition for the Brinepool biome, specifying tile placement and game object spawn regions such as saltstacks and cookiecutter spawners.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/brinepool1"},{"id":"game-scripts/map/bunch_spawner","title":"Bunch Spawner","description":"Spawns groups of entities (bunches) around predefined spawner positions during world generation, enforcing placement rules and spacing constraints.","permalink":"/dst-api-webdocs/docs/game-scripts/map/bunch_spawner"},{"id":"game-scripts/prefabs/buzzardspawner","title":"Buzzardspawner","description":"Spawns buzzards in response to environmental conditions and events, managing their lifecycle, shadow proxies, and seasonal behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/buzzardspawner"},{"id":"game-scripts/prefabs/cave","title":"Cave","description":"Defines the cave world type, including prefabs, assets, spawners, and world initialization logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave"},{"id":"game-scripts/prefabs/cave_vent_mite_spawner","title":"Cave Vent Mite Spawner","description":"A spawner entity that periodically generates cave vent mites in response to nearby players within fumarole areas.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_vent_mite_spawner"},{"id":"game-scripts/prefabs/cavelightmoon","title":"Cavelightmoon","description":"Manages dynamic lighting and spawner behavior for cave moonlight effects, adjusting light parameters based on world state and triggering mob spawns when players are nearby.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavelightmoon"},{"id":"game-scripts/prefabs/crabking_spawner","title":"Crabking Spawner","description":"Spawns the Crab King boss upon timer expiration and manages regeneration when the current Crab King is killed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/crabking_spawner"},{"id":"game-scripts/components/crabkingspawner","title":"Crabkingspawner","description":"Manages the spawning and respawn timing of the Crab King boss during world generation restoration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/crabkingspawner"},{"id":"game-scripts/prefabs/forest","title":"Forest","description":"Configures the Forest world instance by registering prefabs, assets, and world-level components for spawning, environmental effects, and game systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forest"},{"id":"game-scripts/components/forestdaywalkerspawner","title":"Forestdaywalkerspawner","description":"Manages the spawning and state tracking of the Day Walker boss in the Forest world, coordinating with the junk pile and shard-level spawner.","permalink":"/dst-api-webdocs/docs/game-scripts/components/forestdaywalkerspawner"},{"id":"game-scripts/components/frograin","title":"Frograin","description":"Manages the spawning and lifecycle of frogs during rainy spring weather, including logic for lunar rift influence and player-specific spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/frograin"},{"id":"game-scripts/prefabs/houndmound","title":"Houndmound","description":"A structure that spawns hounds periodically and releases them upon damage or death; it also haunts players under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndmound"},{"id":"game-scripts/components/klaussackspawner","title":"Klaussackspawner","description":"Manages spawning and respawning of Klaus sacks in winter, tracking spawn counts and coordinating with world timers and spawner locations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/klaussackspawner"},{"id":"game-scripts/prefabs/lightninggoatherd","title":"Lightninggoatherd","description":"A spawner entity that maintains a herd of lightning goats and periodically generates new members during mating season.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightninggoatherd"},{"id":"game-scripts/components/malbatrossspawner","title":"Malbatrossspawner","description":"Manages the spawning and tracking of Malbatross entities near fish shoals in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/malbatrossspawner"},{"id":"game-scripts/components/maxlightspawner","title":"Maxlightspawner","description":"Spawns and manages a fixed number of light prefabs in a circular pattern around an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maxlightspawner"},{"id":"game-scripts/prefabs/mermhouse","title":"Mermhouse","description":"A structure that spawns Merm minions during the night and regenerates them over time, with special behavior when crafted with an offering pot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mermhouse"},{"id":"game-scripts/prefabs/meteorspawner","title":"Meteorspawner","description":"Creates a classified entity that acts as a meteor spawner by attaching the meteorshower component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/meteorspawner"},{"id":"game-scripts/components/migrationpetsoverrider","title":"Migrationpetsoverrider","description":"Provides a mechanism to override positioning logic for migration pets spawned by the player spawner system.","permalink":"/dst-api-webdocs/docs/game-scripts/components/migrationpetsoverrider"},{"id":"game-scripts/components/minionspawner","title":"Minionspawner","description":"Spawns and manages groups of minion entities around a central spawner entity, tracking their positions, lifecycle, and synchronization across network sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/minionspawner"},{"id":"game-scripts/prefabs/molehill","title":"Molehill","description":"A structure that spawns moles underground and drops loot when dug up.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/molehill"},{"id":"game-scripts/prefabs/monkeyhut","title":"Monkeyhut","description":"A shelter structure that spawns powder monkeys during the day and provides lighting at night.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeyhut"},{"id":"game-scripts/prefabs/moonspiderden","title":"Moonspiderden","description":"A regenerative boss lair that spawns moon spiders and responds to player actions, world state, and environmental events like quakes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonspiderden"},{"id":"game-scripts/prefabs/mushgnome_spawner","title":"Mushgnome Spawner","description":"Manages the controlled spawning of Mushgnome entities in response to player proximity within a defined zone, using the ChildSpawner component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushgnome_spawner"},{"id":"game-scripts/prefabs/mushtree_moon","title":"Mushtree Moon","description":"Creates and configures a light-emitting, shatterable cave tree that spawns spores, drops loot when damaged, and can regrow or decay over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree_moon"},{"id":"game-scripts/prefabs/nightmarelight","title":"Nightmarelight","description":"Spawns and manages nightmare-type enemies in the Caves during nightmare phases, adjusting light intensity and sanity effects dynamically.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarelight"},{"id":"game-scripts/prefabs/oceanfish_shoalspawner","title":"Oceanfish Shoalspawner","description":"Spawns and manages a shoal of medium-sized oceanfish entities in water regions, automatically regenerating and respawning fish over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfish_shoalspawner"},{"id":"game-scripts/prefabs/otterden","title":"Otterden","description":"A structure that spawns and houses otters, stores loot, and reacts to player interaction or combat damage by releasing or aggroing otters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/otterden"},{"id":"game-scripts/prefabs/penguinherd","title":"Penguinherd","description":"A non-networked entity component that manages a herd of penguins, coordinating their spawning via mood cycles and the periodic spawner system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/penguinherd"},{"id":"game-scripts/prefabs/pighouse","title":"Pighouse","description":"Manages a structure that spawns and shelters pigmen, with state-dependent lighting, sound, and damage behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pighouse"},{"id":"game-scripts/prefabs/pond","title":"Pond","description":"Manages frozen, spawning, and environmental state transitions for surface and cave ponds, including seasonal freezing, child mob spawning, acid rain effects, and loot spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pond"},{"id":"game-scripts/prefabs/rabbithole","title":"Rabbithole","description":"Manages a dynamic burrow that spawns rabbits based on season, weather, and player interactions, with support for spring-specific flooded behavior and Rabbit King lucky rabbit spawns.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbithole"},{"id":"game-scripts/prefabs/rabbithouse","title":"Rabbithouse","description":"Manages a structured spawning point for Bunnymen with lighting, burnable physics, and world-state-aware door mechanics in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbithouse"},{"id":"game-scripts/components/rabbitkingmanager","title":"Rabbitkingmanager","description":"Manages the Rabbit King\u2019s lifecycle, including spawning, leashing to players, state transitions (passive/aggressive/lucky), and interaction tracking via carrot-feeding or naughtiness.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rabbitkingmanager"},{"id":"game-scripts/map/static_layouts/retrofit_fumarole","title":"Retrofit Fumarole","description":"Defines a static map layout for a fumarole region in the Caves, using Tiled map format with tile layers and object groups to place props and spawners.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/retrofit_fumarole"},{"id":"game-scripts/components/riftspawner","title":"Riftspawner","description":"Manages the spawning, tracking, and state of lunar and shadow rifts in the game world based on difficulty settings and world conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/riftspawner"},{"id":"game-scripts/prefabs/rockyherd","title":"Rockyherd","description":"Manages the herd system for spawning and maintaining groups of Rocky entities in the world, including seasonal spawning behavior and member population limits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rockyherd"},{"id":"game-scripts/components/schoolspawner","title":"Schoolspawner","description":"Spawns fish schools and triggers special ocean predators like gnarwails and sharks in oceanic regions based on player proximity and environmental conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/schoolspawner"},{"id":"game-scripts/components/shop","title":"Shop","description":"Handles the delivery and spawning of shop-purchased items above the entity\'s position in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shop"},{"id":"game-scripts/prefabs/silk","title":"Silk","description":"A small item used as a craftable material and cat toy, which can be upgraded to increase spider trust when held by a Spider Whisperer.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/silk"},{"id":"game-scripts/prefabs/slurtle","title":"Slurtle","description":"A prefabricated entity that defines the Slurtle and Snurtle creatures, including their combat, locomotion, eating, explosive, and spawner behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slurtle"},{"id":"game-scripts/components/socket_shadow_mimicry","title":"Socket Shadow Mimicry","description":"Manages shadow mimic spawner entities for specific prefab configurations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/socket_shadow_mimicry"},{"id":"game-scripts/prefabs/spiderhole","title":"Spiderhole","description":"A spawner entity that periodically generates spider minions and releases them when mined; it transforms into a mineable rock when fully depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderhole"},{"id":"game-scripts/brains/spiderqueenbrain","title":"Spiderqueenbrain","description":"Controls the AI behavior of the Spider Queen entity, including nest placement, spawning followers, panic responses, and combat logic.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/spiderqueenbrain"},{"id":"game-scripts/prefabs/tumbleweedspawner","title":"Tumbleweedspawner","description":"Spawns and periodically regenerates tumbleweed entities in the world using the ChildSpawner component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tumbleweedspawner"},{"id":"game-scripts/prefabs/wasphive","title":"Wasphive","description":"A hive-like structure that periodically spawns killer bees and reacts to nearby players and attacks by releasing aggressive wasps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wasphive"},{"id":"game-scripts/prefabs/wobster_den","title":"Wobster Den","description":"A water-based structure that spawns and regenerates Wobster creatures over time, interacts with player mining actions and boat collisions, and can transform into a Moonglass Wobster Den during Halloween events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wobster_den"},{"id":"game-scripts/worldsettingsutil","title":"Worldsettingsutil","description":"Provides helper utilities for integrating world-setting-based timer control into core gameplay components like ChildSpawner, Spawner, and Pickable.","permalink":"/dst-api-webdocs/docs/game-scripts/worldsettingsutil"},{"id":"game-scripts/prefabs/wx78_mimicspawner","title":"Wx78 Mimicspawner","description":"Server-only invisible spawner entity that periodically generates Item Mimic entities for WX-78\'s Mimic Heart skill, with density control and cleanup on removal.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_mimicspawner"},{"id":"game-scripts/prefabs/yots_worm_lantern","title":"Yots Worm Lantern","description":"A deployable lantern prefab that transforms into a worm when activated, triggering nearby worm lanterns to activate in sequence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yots_worm_lantern"}],"unlisted":false}}')}}]);